from pybricks.hubs import PrimeHub
from pybricks.parameters import Axis, Direction, Port, Stop
from pybricks.pupdevices import ColorSensor, Motor
from pybricks.robotics import DriveBase

# Set up all devices.
prime_hub = PrimeHub(top_side=Axis.Z, front_side=Axis.X)
color_sensor = ColorSensor(Port.B)
Right = Motor(Port.E, Direction.CLOCKWISE)
Left = Motor(Port.F, Direction.COUNTERCLOCKWISE)
RukaRight = Motor(Port.D, Direction.CLOCKWISE)
RukaLeft = Motor(Port.C, Direction.COUNTERCLOCKWISE)
drive_base = DriveBase(Left, Right, 56, 81)

def ukol_1():
    # config
    drive_base.settings(straight_speed=500)
    drive_base.settings(turn_rate=100)
    # jezditko
    drive_base.straight(50)
    drive_base.turn(45)
    drive_base.straight(500)
    drive_base.turn(30)
    drive_base.straight(180)
    drive_base.turn(-71)
    drive_base.straight(220)
    RukaRight.run_angle(500, -390)

def cisteni_kol():
    drive_base.straight(-50000)

def ukol_2():
    drive_base.straight(-160)
    RukaLeft.control.limits(acceleration=10000)
    RukaLeft.control.limits(speed=2000)
    RukaLeft.run_angle(2000, -510)
    drive_base.turn(-47)
    drive_base.straight(110)
    drive_base.settings(turn_rate=150)
    drive_base.turn(-20, then=Stop.NONE)
    drive_base.turn(40, then=Stop.NONE)
    drive_base.settings(turn_rate=50)
    drive_base.turn(-20)
    drive_base.straight(-50)
    RukaLeft.run_angle(2000, 480)
    RukaRight.run_angle(2000, 370)
    drive_base.settings(straight_speed=50)
    drive_base.straight(50)
    drive_base.settings(straight_speed=500)
    RukaRight.run_angle(2000, -150)
    drive_base.straight(-100)
    drive_base.turn(-70)
    drive_base.straight(500)


# The main program starts here.
print('V:', prime_hub.battery.voltage() / 1000, '   A:', prime_hub.battery.current() / 1000)
drive_base.use_gyro(True)
# config
drive_base.settings(straight_speed=500)
drive_base.settings(turn_rate=100)
# jezditko
ukol_1()
ukol_2()
